mapper.select:
select * from nx_community_dispatch_driver_route
where nx_cddr_plan_id = #{planId}
  and nx_cddr_driver_user_id = #{driverUserId}
limit 1

mapper.update:
update nx_community_dispatch_driver_route
nx_cddr_route_status = #{nxCddrRouteStatus}, nx_cddr_loading_entered_at = #{nxCddrLoadingEnteredAt}, nx_cddr_actual_depart_at = #{nxCddrActualDepartAt}, nx_cddr_stop_count = #{nxCddrStopCount},
where nx_community_dispatch_driver_route_id = #{nxCommunityDispatchDriverRouteId}
